import os
from google.cloud import storage
from subprocess import call

def convert_image(event, context):
    """Cloud Function triggered by Cloud Storage that converts images using ImageMagick"""
    
    # Extract filename and conversion options from event metadata
    bucket_name = event['bucket']
    object_name = event['name']
    filename = os.path.basename(object_name)
    convert_options = event['convertOptions']
    
    # Run convert command with subprocess.call()
    call(['convert', '-quality', '70', '-define', 'png:compression-filter=5', '-define', 'png:compression-level=9', '-interlace', 'Plane', filename])